func isValid(s string) bool {
    st := []rune{}
    pair := map[rune]rune{')':'(', ']':'[', '}':'{'}
    for _, c := range s {
        if v, ok := pair[c]; ok {
            if len(st) == 0 || st[len(st)-1] != v { return false }
            st = st[:len(st)-1]
        } else { st = append(st, c) }
    }
    return len(st) == 0
}
